/**
 * Robustly retrieves environment variables from available sources.
 * In Vite, import.meta.env is preferred for build-time injection.
 * process.env is used as a fallback for values defined via vite.config.ts.
 */
const getVar = (key: string): string => {
  // 1. Try import.meta.env (standard Vite)
  // 2. Try process.env (injected via define in vite.config.ts)
  // 3. Try import.meta.env with VITE_ prefix if key doesn't have it

  const viteKey = key.startsWith('VITE_') ? key : `VITE_${key}`;

  const val = (import.meta.env as any)[viteKey] || 
              (import.meta.env as any)[key] ||
              (process.env as any)[viteKey] ||
              (process.env as any)[key] || 
              '';

  return val;
};

